import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getOnchainNews(chainName, contractAddress) {
  const events = await client.BaseService.getLogEventsByAddress(
    chainName, contractAddress, { startingBlock: "latest" }
  );
  return (events.data?.items ?? []).map(e => ({
    type: e.decoded?.name,
    blockTime: e.block_signed_at,
    summary: JSON.stringify(e.decoded?.params),
  }));
}
